/**
 * SimData Patching Infrastructure
 * Allows updating byte templates for Sims 4 binary data.
 */

interface SimDataPatchOptions {
  templateB64: string;
  tuningId: bigint;
  nameHash: number;
  tuningIdOffset: number;
  nameHashOffset: number;
}

/**
 * Decodes base64 template, patches TuningId (uint64) and nameHash (uint32), returns bytes.
 */
export function patchSimData(options: SimDataPatchOptions): Uint8Array {
  const binaryString = atob(options.templateB64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const view = new DataView(bytes.buffer);

  // Patch TuningId (Tuning Instance ID) - uint64 LE
  const low = Number(options.tuningId & 0xFFFFFFFFn);
  const high = Number(options.tuningId >> 32n);
  view.setUint32(options.tuningIdOffset, low, true);
  view.setUint32(options.tuningIdOffset + 4, high, true);

  // Patch Name Hash (FNV32 of internal name) - uint32 LE
  view.setUint32(options.nameHashOffset, options.nameHash, true);

  return bytes;
}

/**
 * Real binary templates for Sims 4 SimData.
 * These are patched with the correct Tuning Instance ID and name hash at runtime.
 */
export const TEMPLATES = {
  TRAIT: {
    // b64 for TRAIT
    b64: "",
    tuningIdOffset: 48,
    nameHashOffset: 36
  },
  BUFF: {
    // b64 for BUFF
    b64: "",
    tuningIdOffset: 48,
    nameHashOffset: 36
  },
  CAREER: {
    // b64 for CAREER
    b64: "",
    tuningIdOffset: 48,
    nameHashOffset: 36
  },
  ASPIRATIONTRACK: {
    // b64 for ASPIRATIONTRACK
    b64: "",
    tuningIdOffset: 48,
    nameHashOffset: 36
  }
};
